return [
  { json: { email: 'ok@example.com', age: 30 } },
  { json: { email: 'bad', age: 12 } }
];

const schema = z.object({
  email: z.string().email(),
  age: z.number().int().min(18),
});

const result = schema.safeParse($json);

if (!result.success) {
  return {
    json: {
      valid: false,
      errors: result.error.issues.map((i) => i.message),
      input: $json,
    },
  };
}

return {
  json: {
    valid: true,
    data: result.data,
  },
};
